<template>
  <el-tabs v-model="activeTab">
    <el-tab-pane label="常规" name="normal">
      <el-form
        ref="form"
        :model="normalProps"
      >
        <el-form-item
          v-for="(value, key, index) in normalProps"
          :key="index"
          :label="key"
        >
          <el-input v-model="normalProps[key]" />
        </el-form-item>
      </el-form>
    </el-tab-pane>
    <el-tab-pane label="接口" name="api">接口</el-tab-pane>
    <el-tab-pane label="外观" name="appearous">外观</el-tab-pane>
  </el-tabs>
</template>
<script>
import { ElTabs, ElTabPane, ElForm, ElFormItem, ElInput } from 'element-plus';
const disalbedProps = ['renderer', 'path', 'api'];

export default {
  name: 'PropsEditor',
  components: {
    ElTabs,
    ElTabPane,
    ElForm,
    ElFormItem,
    ElInput
  },
  props: {
    value: {
      type: Object,
      required: true
    }
  },
  data() {
    const normalProps = {};
    const apiProps = {};
    const nodeProps = {};

    for (const key in this.value) {
      if (this.value.hasOwnProperty(key) && !disalbedProps.includes(key)) {
        if (Object.prototype.toString.call(this.value[key]) === '[object String]') {
          normalProps[key] = this.value[key];
        }
      }
    }
    return {
      activeTab: 'normal',
      normalProps
    }
  }
}
</script>
